import React, { useEffect, useState } from "react";
import api from "../api";

function UserDashboard() {
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);
  const [mostOrdered, setMostOrdered] = useState([]);
  const [loadingUser, setLoadingUser] = useState(true);
  const [loadingOrders, setLoadingOrders] = useState(true);
  const [loadingMostOrdered, setLoadingMostOrdered] = useState(true);

  const storedUser = JSON.parse(localStorage.getItem("user"));

  // Fetch user profile
  const fetchUser = async () => {
    try {
      setLoadingUser(true);
      const res = await api.post(`/user/${storedUser.id}`);
      setUser(res.data);
    } catch (err) {
      console.error("Error fetching user:", err);
    } finally {
      setLoadingUser(false);
    }
  };

  // Fetch user orders
  const fetchOrders = async () => {
    try {
      setLoadingOrders(true);
      const res = await api.get(`/orders/user/${storedUser.id}`);
      setOrders(res.data);
    } catch (err) {
      console.error("Failed to fetch order history:", err);
    } finally {
      setLoadingOrders(false);
    }
  };

  // Fetch most ordered foods
  const fetchMostOrdered = async () => {
    try {
      setLoadingMostOrdered(true);
      const res = await api.get("/orders/most-ordered");
      setMostOrdered(res.data);
    } catch (err) {
      console.error("Failed to fetch most ordered food:", err);
    } finally {
      setLoadingMostOrdered(false);
    }
  };

  useEffect(() => {
    fetchUser();
    fetchOrders();
    fetchMostOrdered();
  }, []);

  if (loadingUser) return <div className="text-center mt-5">Loading user...</div>;
    <div className="col-md-4">
          <div className="card shadow-sm border-0 h-100">
            <div className="card-body text-center">
              
              <h5 className="card-title">{user.name}</h5>
              <p className="card-text">🎓 {user.Degree}</p>
              <p className="text-muted small">Roll No: {user.RollNo}</p>
              <span className="badge bg-primary">{user.role}</span>
            </div>
          </div>
        </div>

  return (
    <div className="container mt-4">
      {/* Header */}
      <div className="text-center mb-5">
        <h2 className="fw-bold">Welcome, {user.name} 👋</h2>
        <p className="text-muted">Here’s your dashboard overview</p>
      </div>

      <div className="row g-4">
        {/* Profile Section */}
      

        {/* Orders Section */}
        <div className="col-md-8">
          <div className="card shadow-sm border-0 h-100">
            <div className="card-body">
              <h4 className="card-title mb-4">📦 Your Orders</h4>

              {loadingOrders ? (
                <p className="text-center text-muted">Loading orders...</p>
              ) : orders.length === 0 ? (
                <p className="text-muted">You have no orders yet.</p>
              ) : (
                <>
                  <p>Total Orders: <strong>{orders.length}</strong></p>
                  <div className="list-group">
                    {orders.map((order, index) => (
                      <div key={index} className="list-group-item mb-3">
                        <div className="d-flex justify-content-between">
                          <div>
                            <h6>Order ID: <code>{order.token}</code></h6>
                            <p className="mb-1">Status: <strong>{order.status}</strong></p>
                            <p className="mb-1">Payment: <strong>{order.payment}</strong></p>
                            <p className="mb-1">Total Price: ₹{order.totalPrice}</p>
                          </div>
                          <div>
                            <h6>Items:</h6>
                            <ul className="list-unstyled">
                              {order.items?.map((item, idx) => (
                                <li key={idx}>
                                  🍔 {item.food?.name} × {item.quantity}
                                </li>
                              ))}
                            </ul>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Most Ordered Food Section */}
      <div className="row g-4 mt-5">
        <div className="col-12">
          <div className="card shadow-sm border-0">
            <div className="card-body">
              <h4 className="card-title mb-4">🔥 Most Ordered Foods</h4>

              {loadingMostOrdered ? (
                <p className="text-center text-muted">Loading most ordered foods...</p>
              ) : mostOrdered.length === 0 ? (
                <p className="text-muted">No orders yet.</p>
              ) : (
                <div className="d-flex flex-wrap">
                  {mostOrdered.map((food, idx) => (
                    <div key={idx} className="card m-2" style={{ width: '150px' }}>
                      <img
                        src={food.img ? `http://localhost:5000${food.img}` : 'https://via.placeholder.com/100'}
                        className="card-img-top"
                        alt={food.name}
                      />
                      <div className="card-body text-center p-2">
                        <h6 className="card-title mb-1">{food.name}</h6>
                        <p className="mb-0 text-muted">Ordered: {food.quantity} times</p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default UserDashboard;
